SELECT AVG(crime_rate) AS average_crime_rate
FROM crime_statistics
WHERE zone_id = 1;

SELECT AVG(sale_price) AS average_sale_price
FROM properties
WHERE crime_rate > (SELECT AVG(crime_rate) FROM properties);

SELECT AVG(sale_price) AS average_sale_price
FROM properties
WHERE property_type = 'residential' AND listing_status = 'sold';

SELECT property_id, median_value
FROM properties
ORDER BY median_value DESC;

SELECT AVG(sale_price) AS average_sale_price
FROM properties
WHERE crime_rate < 1 AND median_value > 500000;
